onClick:
{{
  (async () => {
    // 1. Kiểm tra điều kiện đầu vào (Bao gồm cả Loại máy dùng)
    if (!inp_MaCongCu.text || !inp_SoLuong.text || !sel_NhanVien.selectedOptionValue || !inp_MaySuDung.text) {
      showAlert('Vui lòng điền đầy đủ thông tin bắt buộc (kể cả Loại máy dùng)!', 'warning');
      return; // Dừng chạy tiếp nếu thiếu thông tin
    }

    try {
      // 2. Thực thi lệnh Xuất kho
      await Action_XuatKho.run();

      // 3. Thông báo thành công
      showAlert('Xuất kho thành công! / 出库成功!', 'success');

      // 4. LÀM MỚI TẤT CẢ CÁC BẢNG LIÊN QUAN (Tuần tự và an toàn)
      await Get_Bang_Tool.run();         // Load lại bảng danh mục/tồn kho
      await Get_LS_Xuat.run();           // Load lại bảng lịch sử xuất
      await Get_Inventory_Data.run();    // Cập nhật ngay số liệu sang Bảng Kiểm Kê

      // 5. Reset lại Form nhập liệu
      resetWidget('Form_Xuat_Nhap_1', true);

    } catch (err) {
      // 6. Xử lý lỗi nếu có
      showAlert('❌ Lỗi: ' + err.message, 'error');
    }
  })()
}}
